draw(O--Z[4]);
draw(Z[4]--Z[0]+Z[4], blue); 
draw(O--Z[0]+Z[4]); 
dot("$e^{7\pi i/60}$", Z[0], dir(Z[0])); 
dot("$e^{47\pi i/60}$", Z[4], NW); 
